  "show_code_block_in_summary": "\u041F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0442\u044C CodeBlock \u0432 \u043A\u0440\u0430\u0442\u043A\u043E\u043C \u043E\u043F\u0438\u0441\u0430\u043D\u0438\u0438",
