  "default_sort_type": "\u0422\u0438\u043F \u0441\u043E\u0440\u0442\u0443\u0432\u0430\u043D\u043D\u044F \u0437\u0430 \u0437\u0430\u043C\u043E\u0432\u0447\u0443\u0432\u0430\u043D\u043D\u044F\u043C",
  "default_sort_type_desc": "\u0412\u0441\u0442\u0430\u043D\u043E\u0432\u0456\u0442\u044C \u043C\u0435\u0442\u043E\u0434 \u0441\u043E\u0440\u0442\u0443\u0432\u0430\u043D\u043D\u044F \u0437\u0430 \u0437\u0430\u043C\u043E\u0432\u0447\u0443\u0432\u0430\u043D\u043D\u044F\u043C \u043F\u0440\u0438 \u0432\u0456\u0434\u043A\u0440\u0438\u0442\u0442\u0456 \u0441\u0456\u0442\u043A\u043E\u0432\u043E\u0433\u043E \u0432\u0438\u0433\u043B\u044F\u0434\u0443",
  "note_title_field": '\u041D\u0430\u0437\u0432\u0430 \u043F\u043E\u043B\u044F "\u0417\u0430\u0433\u043E\u043B\u043E\u0432\u043E\u043A \u043D\u043E\u0442\u0430\u0442\u043A\u0438"',
  "note_title_field_desc": "\u0412\u0441\u0442\u0430\u043D\u043E\u0432\u0456\u0442\u044C \u043D\u0430\u0437\u0432\u0443 \u043F\u043E\u043B\u044F \u0443 frontmatter \u0434\u043B\u044F \u0432\u0438\u043A\u043E\u0440\u0438\u0441\u0442\u0430\u043D\u043D\u044F \u044F\u043A \u0437\u0430\u0433\u043E\u043B\u043E\u0432\u043A\u0430 \u043D\u043E\u0442\u0430\u0442\u043A\u0438",
  "note_summary_field": '\u041D\u0430\u0437\u0432\u0430 \u043F\u043E\u043B\u044F "\u041E\u043F\u0438\u0441 \u043D\u043E\u0442\u0430\u0442\u043A\u0438"',
  "note_summary_field_desc": "\u0412\u0441\u0442\u0430\u043D\u043E\u0432\u0456\u0442\u044C \u043D\u0430\u0437\u0432\u0443 \u043F\u043E\u043B\u044F \u0443 frontmatter \u0434\u043B\u044F \u0432\u0438\u043A\u043E\u0440\u0438\u0441\u0442\u0430\u043D\u043D\u044F \u044F\u043A \u043E\u043F\u0438\u0441\u0443 \u043D\u043E\u0442\u0430\u0442\u043A\u0438",
  "modified_date_field": '\u041D\u0430\u0437\u0432\u0430 \u043F\u043E\u043B\u044F "\u0414\u0430\u0442\u0430 \u0437\u043C\u0456\u043D\u0438"',
  "modified_date_field_desc": "\u0412\u0441\u0442\u0430\u043D\u043E\u0432\u0456\u0442\u044C \u043D\u0430\u0437\u0432\u0443 \u043F\u043E\u043B\u044F \u0443 frontmatter \u0434\u043B\u044F \u0432\u0438\u043A\u043E\u0440\u0438\u0441\u0442\u0430\u043D\u043D\u044F \u044F\u043A \u0434\u0430\u0442\u0438 \u0437\u043C\u0456\u043D\u0438 (\u043F\u0456\u0434\u0442\u0440\u0438\u043C\u0443\u0454 \u043A\u0456\u043B\u044C\u043A\u0430 \u043D\u0430\u0437\u0432 \u043F\u043E\u043B\u0456\u0432, \u0440\u043E\u0437\u0434\u0456\u043B\u0435\u043D\u0438\u0445 \u043A\u043E\u043C\u0430\u043C\u0438)",
  "created_date_field": '\u041D\u0430\u0437\u0432\u0430 \u043F\u043E\u043B\u044F "\u0414\u0430\u0442\u0430 \u0441\u0442\u0432\u043E\u0440\u0435\u043D\u043D\u044F"',
  "created_date_field_desc": "\u0412\u0441\u0442\u0430\u043D\u043E\u0432\u0456\u0442\u044C \u043D\u0430\u0437\u0432\u0443 \u043F\u043E\u043B\u044F \u0443 frontmatter \u0434\u043B\u044F \u0432\u0438\u043A\u043E\u0440\u0438\u0441\u0442\u0430\u043D\u043D\u044F \u044F\u043A \u0434\u0430\u0442\u0438 \u0441\u0442\u0432\u043E\u0440\u0435\u043D\u043D\u044F (\u043F\u0456\u0434\u0442\u0440\u0438\u043C\u0443\u0454 \u043A\u0456\u043B\u044C\u043A\u0430 \u043D\u0430\u0437\u0432 \u043F\u043E\u043B\u0456\u0432, \u0440\u043E\u0437\u0434\u0456\u043B\u0435\u043D\u0438\u0445 \u043A\u043E\u043C\u0430\u043C\u0438)",
  "grid_item_width": "\u0428\u0438\u0440\u0438\u043D\u0430 \u0435\u043B\u0435\u043C\u0435\u043D\u0442\u0430 \u0441\u0456\u0442\u043A\u0438",
